const msg = $('Grocery Telegram Trigger').item.json.message || {};
const text = (msg.text || '').trim();
const from = msg.from || {};
const isRefresh = /^\/refresh\b/i.test(text);

let rest = text;
let quantity = '1';
const qm = rest.match(/^(\d+)\s+(.*)$/);
if (qm) { quantity = qm[1]; rest = qm[2]; }
let estimated = null;
const pm = rest.match(/R\s?(\d+(?:\.\d+)?)/i);
if (pm) { estimated = parseFloat(pm[1]); rest = rest.replace(pm[0], '').trim(); }
const itemName = rest.replace(/\s+/g, ' ').trim();

return [{ json: {
  mode: isRefresh ? 'refresh' : 'additem',
  text,
  chatId: msg.chat.id,
  messageId: msg.message_id,
  fromId: from.id || null,
  fromName: from.first_name || from.username || 'Someone',
  itemName,
  quantity,
  estimatedPrice: estimated,
} }];

const r = $json;
let lines;
if (r.stale) {
  lines = [r.message || 'Refresh failed — showing last successful fetch.'];
} else {
  const d = r.last_scraped_at ? new Date(r.last_scraped_at).toISOString().slice(0,10) : 'now';
  lines = [`🛍️ Specials refreshed — ${r.scraped_count} deals (prices as of ${d}).`];
}
return [{ json: { message: lines.join('\n') } }];

const p = $('Parse Message').item.json;
const sp = $('Specials Match').first().json || {};
const calc = $('Projected Remaining').first().json || {};

const lines = [`✅ Added "${p.itemName}"${p.quantity && p.quantity !== '1' ? ' x' + p.quantity : ''} for ${p.fromName}.`];

if (sp && sp.store) {
  const price = sp.price != null ? ` R${Number(sp.price).toFixed(2)}` : '';
  const until = sp.valid_until ? ` until ${sp.valid_until}` : '';
  const label = sp.item_keyword || sp.description;
  lines.push(`🏷️ On special at ${sp.store}: ${label}${price}${until} (prices as of ${sp.as_of}).`);
}

if (calc.budget == null) {
  lines.push('(Set a monthly Groceries budget to see projected remaining.)');
} else {
  const budget = Number(calc.budget);
  const bought = Number(calc.bought);
  const pendingEst = Number(calc.pending_est);
  const proj = budget - bought - pendingEst;
  lines.push(`💰 Projected remaining: R${proj.toFixed(2)} of R${budget.toFixed(2)} — if all pending items are bought at estimate (R${bought.toFixed(2)} bought, R${pendingEst.toFixed(2)} pending est. this month).`);
}

return [{ json: { message: lines.join('\n') } }];
